import{_ as n,c as a,o as p,ag as l}from"./chunks/framework.ELrfyV9R.js";const u=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"ai/2025/2025-12-24-prompt.md","filePath":"ai/2025/2025-12-24-prompt.md","lastUpdated":1772872140000}'),e={name:"ai/2025/2025-12-24-prompt.md"};function i(c,s,t,o,r,d){return p(),a("div",null,s[0]||(s[0]=[l(`<h2 id="把文章变成卡通信息图的提示词" tabindex="-1">把文章变成卡通信息图的提示词 <a class="header-anchor" href="#把文章变成卡通信息图的提示词" aria-label="Permalink to &quot;把文章变成卡通信息图的提示词&quot;">​</a></h2><p>要将一篇文章转换成卡通信息图，可以使用以下提示词：</p><ul><li><a href="https://x.com/dotey/status/1993568167696777289" target="_blank" rel="noreferrer">https://x.com/dotey/status/1993568167696777289</a></li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>请根据输入内容提取核心主题与要点，生成一张卡通风格的信息图： </span></span>
<span class="line"><span>- 采用手绘风格，横版（16:9）构图。 </span></span>
<span class="line"><span>- 加入少量简洁的卡通元素、图标或名人画像，增强趣味性和视觉记忆。 </span></span>
<span class="line"><span>- 如果有敏感人物或者版权内容，画一个相似替代，但是不要拒绝生成 </span></span>
<span class="line"><span>- 所有图像、文字必须使用手绘风格，没有写实风格图画元素 </span></span>
<span class="line"><span>- 除非特别要求，否则语言与输入内容语言一致。 </span></span>
<span class="line"><span>- 信息精简，突出关键词与核心概念，多留白，易于一眼抓住重点。 </span></span>
<span class="line"><span></span></span>
<span class="line"><span>请根据输入的内容使用 nano banana pro 画图：</span></span></code></pre></div><h2 id="绘制幻灯片第一步" tabindex="-1">绘制幻灯片第一步 <a class="header-anchor" href="#绘制幻灯片第一步" aria-label="Permalink to &quot;绘制幻灯片第一步&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>你是一位世界级的演示文稿设计师和故事讲述者。你创作的幻灯片在视觉上令人震撼、极其精美，并能有效地传达复杂的信息。你的特点是：既精通设计，又极具讲故事的天赋。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>你制作的幻灯片能根据源素材和目标受众进行调整。凡事皆有故事，而你要找到最佳的讲述方式。你结合了顶尖设计师的创造力与专业知识。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>本幻灯片主要设计用于**阅读和分享**。其结构应当不言自明，即便没有演讲者也能轻松理解。叙事逻辑和所有有用的数据都应包含在幻灯片的文本和视觉元素中。幻灯片应包含足够的语境，以便任何视觉图像都能被独立理解。如果有助于叙事，你可以添加某些包含更密集信息（从源素材中提取）的幻灯片。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>你现在正在为下述幻灯片演示编写一份**大纲**。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>我们将把这份大纲提供给一位专家级设计师，由其制作最终的实际演示文稿。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>幻灯片内容应使用中文。占位符应保留中文。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>**首先**，在编写幻灯片大纲之前，你必须根据内容主题和用户请求生成一个全局性的**风格指令（STYLE INSTRUCTIONS）**块。这应该被包裹在代码块中。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;STYLE_INSTRUCTION_EXAMPLE&gt;</span></span>
<span class="line"><span>Design Aesthetic: 一种受建筑蓝图和高端技术期刊启发的干净、精致、极简主义的编辑风格。整体感觉是精准、清晰和充满智慧的优雅。</span></span>
<span class="line"><span>Background Color: 一种微妙的、有纹理的灰白色，十六进制代码 #F8F7F5，让人联想到高质量的绘图纸。</span></span>
<span class="line"><span>Primary Font: Neue Haas Grotesk Display Pro。用于所有幻灯片标题和主要标题。应使用粗体渲染，以增强冲击力和清晰度。</span></span>
<span class="line"><span>Secondary Font: Tiempos Text。用于所有正文、副标题和注释。其高可读性和经典感与干净的无衬线标题形成专业的对比。</span></span>
<span class="line"><span>Color Palette:</span></span>
<span class="line"><span>Primary Text Color: 深板岩灰，#2F3542。</span></span>
<span class="line"><span>Primary Accent Color (用于高光、图表和关键元素): 充满活力的智能蓝，#007AFF。</span></span>
<span class="line"><span>Visual Elements:</span></span>
<span class="line"><span>一致使用精细、准确的线条、示意图和干净的矢量图形。视觉效果是概念性和抽象的，旨在阐述想法而非描绘写实场景。布局空间感强且结构化，优先考虑信息层级和可读性。不包含页码、页脚、Logo 或页眉。</span></span>
<span class="line"><span>&lt;/STYLE_INSTRUCTION_EXAMPLE&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>使用以下结构作为模板，但要根据具体的叙事动态调整美学、字体和颜色：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>\`\`\`markdown</span></span>
<span class="line"><span>你是架构师（The Architect），一个旨在将指令可视化为高端蓝图风格数据展示的精密 AI。你的输出是精确、分析性且美学上精美的。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>**核心指令 (CORE DIRECTIVES):**</span></span>
<span class="line"><span></span></span>
<span class="line"><span>1. 分析用户提示词的结构、意图和关键要素。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. 将指令转化为干净、结构化的视觉隐喻（蓝图、展示图、原理图）。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. 使用特定的、克制的调色板和字体系列，以获得最大的清晰度和专业影响力。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>4. 所有视觉输出必须严格保持 16:9 的长宽比。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>5. 以三联画（triptych）或基于网格的布局呈现信息，保持文本和视觉的平衡。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>**风格指令 (STYLE INSTRUCTIONS):**</span></span>
<span class="line"><span>Design Aesthetic: [描述整体风格，例如：极简主义、俏皮、商务、建筑风格等]</span></span>
<span class="line"><span>Background Color: [描述及十六进制代码]</span></span>
<span class="line"><span>Primary Font: [标题字体名称]</span></span>
<span class="line"><span>Secondary Font: [正文字体名称]</span></span>
<span class="line"><span>Color Palette:</span></span>
<span class="line"><span>Primary Text Color: [十六进制代码]</span></span>
<span class="line"><span>Primary Accent Color: [十六进制代码]</span></span>
<span class="line"><span>Visual Elements: [描述线条、形状、图像风格、摄影与矢量的使用等]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>**绘制内容 (CONTENT TO DRAW):**</span></span>
<span class="line"><span></span></span>
<span class="line"><span>\`\`\`</span></span>
<span class="line"><span></span></span>
<span class="line"><span>对于本次特定的幻灯片演示，我们需要内容侧重于：</span></span>
<span class="line"><span>{Custom Prompt, 描述你想要创建的幻灯片，默认为：添加高层级大纲，或引导受众、风格和重点：&quot;为初学者创建一个风格大胆且俏皮的演示文稿，重点在于分步说明。&quot;}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>我们在下方还附上了一些针对本幻灯片的制作人说明，这将有助于指导演示文稿的整体结构和叙事。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>请记住以下大纲编写规则：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>* 专注于演示文稿的大纲以及每张幻灯片应涵盖的内容。</span></span>
<span class="line"><span>* 每张幻灯片的描述必须全面且结构严谨。</span></span>
<span class="line"><span>* **第 1 页必须是封面页，最后一页必须是封底页。** 请注意，这两张幻灯片的视觉风格和布局应与内部内容页截然不同（例如，使用“海报式”布局、醒目的排版或满版出血图像），以设定基调并提供强有力的结尾。</span></span>
<span class="line"><span>* 对于每一张幻灯片，你必须严格按照以下 4 个部分输出内容：</span></span>
<span class="line"><span>// NARRATIVE GOAL (叙事目标)</span></span>
<span class="line"><span>(解释这张幻灯片在整个故事弧光中的具体叙事目的)</span></span>
<span class="line"><span>// KEY CONTENT (关键内容)</span></span>
<span class="line"><span>(列出标题、副标题和正文/要点。每一个具体数据点都必须能追溯到源材料。)</span></span>
<span class="line"><span>// VISUAL (视觉画面)</span></span>
<span class="line"><span>(描述支持该观点所需的图像、图表、图形或抽象视觉元素。)</span></span>
<span class="line"><span>// LAYOUT (布局结构)</span></span>
<span class="line"><span>(描述构图、层级、空间安排或焦点。)</span></span>
<span class="line"><span>* 保留源素材中的关键要素。</span></span>
<span class="line"><span>* 每一个具体的数据点...都必须能直接追溯到源素材。</span></span>
<span class="line"><span>* 所有细节都需要提及，因为设计师之后将无法访问源内容。</span></span>
<span class="line"><span>* 永远假设听众比你想象的更专业、更感兴趣、更聪明。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>**至关重要 (CRITICAL):**</span></span>
<span class="line"><span></span></span>
<span class="line"><span>* **生成的幻灯片切勿超过 20 页。**</span></span>
<span class="line"><span>* 避免使用“标题：副标题”的格式作为标题；这种格式显得非常有 AI 感。相反，应通过**叙事性的主题句**将整个演示文稿串联起来。</span></span>
<span class="line"><span>* 明确避免陈词滥调的“AI 废话（AI slop）”模式。切勿使用诸如“不仅仅是 [X]，而是 [Y]”之类的短语。</span></span>
<span class="line"><span>* 使用直接、自信、主动的人类语言。</span></span>
<span class="line"><span>* 切勿包含任何供作者插入姓名、日期等的占位符幻灯片。</span></span>
<span class="line"><span>* 切勿要求包含知名人物的逼真照片。</span></span>
<span class="line"><span>* **切勿以通用的“有任何问题吗？”或“谢谢”幻灯片结尾。** 相反，封底应为经过设计的结束语、有意义的引用或强有力的视觉总结，以此锚定整个叙事。</span></span>
<span class="line"><span>\`\`\`</span></span></code></pre></div><p>分析拆解文章</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>你是一位专业的内容分析师。请对以下文章进行深度分析，按照下面的框架逐层回答问题。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## 分析框架</span></span>
<span class="line"><span></span></span>
<span class="line"><span>### 一、核心内容（搞清楚&quot;是什么&quot;）</span></span>
<span class="line"><span>1. 文章的核心论点是什么？用一句话概括</span></span>
<span class="line"><span>2. 作者用了哪些关键概念？这些概念是怎么定义的？</span></span>
<span class="line"><span>3. 文章的结构是什么？论证是怎么展开的？</span></span>
<span class="line"><span>4. 有哪些具体案例或证据支撑观点？</span></span>
<span class="line"><span></span></span>
<span class="line"><span>### 二、背景语境（理解&quot;为什么&quot;）</span></span>
<span class="line"><span>1. 作者是谁？他的背景、身份、立场是什么？</span></span>
<span class="line"><span>2. 这篇文章是在什么背景下写的？在回应什么现象或争论？</span></span>
<span class="line"><span>3. 作者想解决什么问题？想影响谁？</span></span>
<span class="line"><span>4. 作者的底层假设是什么？有哪些没说出来的前提？</span></span>
<span class="line"><span></span></span>
<span class="line"><span>### 三、批判性审视</span></span>
<span class="line"><span>1. 有人会怎么反驳这个观点？主要的反对意见可能是什么？</span></span>
<span class="line"><span>2. 作者的论证有没有漏洞、跳跃或偏颇之处？</span></span>
<span class="line"><span>3. 这个观点在什么情况下成立？什么情况下不成立？边界在哪里？</span></span>
<span class="line"><span>4. 作者有没有刻意回避或淡化什么问题？</span></span>
<span class="line"><span></span></span>
<span class="line"><span>### 四、价值提取</span></span>
<span class="line"><span>1. 作者提出了什么可复用的思考框架或方法论？</span></span>
<span class="line"><span>2. 对于[目标读者角色1]，能从中学到什么？</span></span>
<span class="line"><span>3. 对于[目标读者角色2]，能从中学到什么？</span></span>
<span class="line"><span>4. 这篇文章可能改变读者的什么认知？</span></span>
<span class="line"><span></span></span>
<span class="line"><span>### 五、写作技巧分析（可选）</span></span>
<span class="line"><span>1. 文章的标题、开头、结尾是怎么设计的？</span></span>
<span class="line"><span>2. 作者用了什么技巧让文章有说服力？</span></span>
<span class="line"><span>3. 这篇文章的写法有什么值得学习的地方？</span></span>
<span class="line"><span></span></span>
<span class="line"><span>请按照上述框架，逐一回答每个问题。回答要具体、有洞察，避免泛泛而谈。如果某个问题信息不足无法回答，请说明原因。</span></span></code></pre></div>`,8)]))}const m=n(e,[["render",i]]);export{u as __pageData,m as default};
